import { createRouter, createWebHistory } from 'vue-router'
import { useAuthStore } from '@/service/auth'


import NotFound from '@/views/NotFound.vue'

import AppLayout from '@/layout/AppLayout.vue'

const routes = [
  {
    path: '/',
    component: AppLayout,
    children: [
      {
        path: '/',
        name: 'home',
        component: () => import('@/views/HomeAdmin.vue')
      },
      {
        path: '/',
        name: 'homeuser',
        component: () => import('@/views/HomeUser.vue')
      },
      {
        path: '/finanzasa',
        name: 'finanzasa',
        component: () => import('@/views/finanzasa/Finanzas.vue')
      },
      {
        path: '/finanzasu',
        name: 'finanzasu',
        component: () => import('@/views/finanzasu/Finanzas.vue')
      },
      {
        path: '/administracion',
        name: 'administracion',
        component: () => import('@/views/administracion/Administracion.vue')
      },
      {
        path: '/configuracion',
        name: 'configuracion',
        component: () => import('@/views/configuracion/Configuracion.vue')
      },
      {
        path: '/about',
        name: 'about',
        component: () => import('@/views/About.vue')
      }
    ]
  },
  {
    path: '/auth/login',
    name: 'login',
    component: () => import('@/views/login/Login.vue')
  },
  {//catch 404
    path: '/:catchAll(.*)',
    name: 'notFound',
    component: NotFound
  }
  //Route Guards
]

const router = createRouter({
  history: createWebHistory(process.env.BASE_URL),
  routes
})

